import json,re,statistics as st
G={r['id']:r['article'] for r in map(json.loads,open('gemini-2.5-pro-deepresearch.jsonl'))}
O={r['id']:r['article'] for r in map(json.loads,open('openai-deepresearch.jsonl'))}
def body(a):
    ms=[m.start() for m in re.finditer(r'^1\.\s+\S.*https?://',a,re.M)]
    a=a[:ms[-1]] if ms else a
    a=re.sub(r'^#+.*\$','',a,flags=re.M); a=re.sub(r'^\|.*\$','',a,flags=re.M); return a
def sents(p): return [s for s in re.split(r'(?<=[.!?])\s+',p.strip()) if len(s.split())>=4]
cg=lambda s: bool(re.search(r'[a-zA-Z.,;:)\]]\s?\d{1,3}\b',s))
# uncited rate by position in paragraph (gemini)
pos={i:[0,0] for i in range(5)}
coda=0;multi=0;coda_tension=0;other=0;other_tension=0
T=re.compile(r'tension|trade-?off|however|conversely|implication|paradox|conflict|discrepan',re.I)
for a in G.values():
    for p in body(a).split('\n\n'):
        ss=sents(p)
        if len(ss)<2: continue
        c=[cg(s) for s in ss]; multi+=1
        for i,x in enumerate(c[:4]): pos[i][0]+=1; pos[i][1]+= (0 if x else 1)
        pos[4][0]+=1; pos[4][1]+= (0 if c[-1] else 1)
        # cited body + uncited coda
        if not c[-1] and any(c[:-1]):
            coda+=1; coda_tension += bool(T.search(p))
        else:
            other+=1; other_tension += bool(T.search(p))
print('GEMINI uncited rate by paragraph position:')
for i in range(5): print('  pos%s %.1f%%'%(i if i<4 else '4(last)',100*pos[i][1]/pos[i][0]))
print('cited-body + uncited-coda paragraphs: %.1f%% of multi-sent paras'%(100*coda/multi))
print('  tension language in coda paras %.0f%% vs other %.0f%%'%(100*coda_tension/coda,100*other_tension/other))
print()
for D,n in ((G,'GEM'),(O,'OAI')):
    t=sum(1 for a in D.values() if T.search(a))
    h=sum(1 for a in D.values() if re.search(r'^#+.*(tension|trade-?off|challenge|conflict|discrepan|limitation|caveat|uncertaint|risk)',a,re.M|re.I))
    print('%s reports w/ tension language %d/100 ; w/ such a HEADING %d/100'%(n,t,h))
"
